bool
tlPoseAnimChunk16::operator==(const tlDataChunk& a)
{

    const tlPoseAnimChunk16* aptr = dynamic_cast<const tlPoseAnimChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(version == aptr->version))
    {
        return false;
    }
    if(strcmp(skeletonname, aptr->skeletonname) != 0)
    {
        return false;
    }
    if(!(numframes == aptr->numframes))
    {
        return false;
    }
    if(!(framerate == aptr->framerate))
    {
        return false;
    }
    if(!(cyclic == aptr->cyclic))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

