tlDataChunk*
tlPoseAnimChunk16::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case P3D_JOINT_LIST:
        dch = new tlPoseJointListChunk16(&ch);
        break;
    case P3D_POSE_ANIM_MIRRORED:
        dch = new tlPoseAnimMirroredChunk16(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

