tlDataChunk*
tlAnimChannelChunk16::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case P3D_CHANNEL_1DOF:
        dch = new tlChannel1DOFChunk16(&ch);
        break;
    case P3D_CHANNEL_3DOF:
        dch = new tlChannel3DOFChunk16(&ch);
        break;
    case P3D_CHANNEL_1DOF_ANGLE:
        dch = new tlChannel1DOFAngleChunk16(&ch);
        break;
    case P3D_CHANNEL_3DOF_ANGLE:
        dch = new tlChannel3DOFAngleChunk16(&ch);
        break;
    case P3D_CHANNEL_QUATERNION:
        dch = new tlChannelQuaternionChunk16(&ch);
        break;
    case P3D_CHANNEL_STATIC:
        dch = new tlChannelStaticVectorChunk16(&ch);
        break;
    case P3D_CHANNEL_STATIC_ANGLE:
        dch = new tlChannelStaticAngleChunk16(&ch);
        break;
    case P3D_CHANNEL_STATIC_QUATERNION:
        dch = new tlChannelStaticQuaternionChunk16(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

