tlChannel1DOFChunk16::~tlChannel1DOFChunk16()
{

    if(constants != NULL){
        delete[] constants;
    }
    if(timeindex != NULL){
        delete[] timeindex;
    }
    if(frames != NULL){
        delete[] frames;
    }
}

tlChannel1DOFChunk16::tlChannel1DOFChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_CHANNEL_1DOF);
    ident = P3D_CHANNEL_1DOF;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numkeys = f->GetLong();
    mapping = f->GetLong();
    numconstants = f->GetLong();
    constants = new float[numconstants];
    for(i = 0; i < numconstants; i++)
    {
        constants[i] = f->GetFloat();
    }
    timeindex = new unsigned short[numkeys];
    for(i = 0; i < numkeys; i++)
    {
        timeindex[i] = f->GetWord();
    }
    frames = new float[numkeys];
    for(i = 0; i < numkeys; i++)
    {
        frames[i] = f->GetFloat();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_CHANNEL_1DOF);
    }
}

