void
tlChannel1DOFChunk16::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(numkeys);
        f->PutLong(mapping);
        f->PutLong(numconstants);
    for(i = 0; i < numconstants ; i++)
    {
        f->PutFloat(constants[i]);
    }
    for(i = 0; i < numkeys ; i++)
    {
        f->PutWord(timeindex[i]);
    }
    for(i = 0; i < numkeys ; i++)
    {
        f->PutFloat(frames[i]);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlChannel1DOFChunk16::Print(int indent, unsigned int printdepth, unsigned int typemask)
{
    unsigned int i;

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlChannel1DOFChunk16 (%4x)\n",indent,"",(int) ident);
    printf("%*s  NumKeys      = %ld\n",indent,"",numkeys);
    printf("%*s  Mapping      = %ld\n",indent,"",mapping);
    printf("%*s  NumConstants = %ld\n",indent,"",numconstants);
    printf("%*s  Constants:\n",indent,"");
    for( i=0; i < numconstants; i++)
    {
         printf("%*s    %d %f\n",indent,"",i,constants[i]);
    }
    printf("%*s  TimeIndex:\n",indent,"");
    for( i=0; i < numkeys; i++)
    {
         printf("%*s    %d %d\n",indent,"",i,timeindex[i]);
    }
    printf("%*s  Frames:\n",indent,"");
    for( i=0; i < numkeys; i++)
    {
         printf("%*s    %d %f\n",indent,"",i,frames[i]);
    }

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlChannel1DOFChunk16::PrintFormatted(int indent)
{
    unsigned int i;
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # NumKeys     \n",indent,"",numkeys);
    printf("%*s  int   %12ld # Mapping     \n",indent,"",mapping);
    printf("%*s  int   %12ld # NumConstants\n",indent,"",numconstants);
    printf("%*s  repeat 1 float # Constants   \n",indent,"");
    for( i=0; i < numconstants; i++)
    {
         printf("%*s    %12f\n",indent,"",constants[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    printf("%*s  repeat 1 short # TimeIndex   \n",indent,"");
    for( i=0; i < numkeys; i++)
    {
         printf("%*s    %12d\n",indent,"",timeindex[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    printf("%*s  repeat 1 float # Frames      \n",indent,"");
    for( i=0; i < numkeys; i++)
    {
         printf("%*s    %12f\n",indent,"",frames[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

