tlChannel3DOFChunk16::tlChannel3DOFChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_CHANNEL_3DOF);
    ident = P3D_CHANNEL_3DOF;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numkeys = f->GetLong();
    timeindex = new unsigned short[numkeys];
    for(i = 0; i < numkeys; i++)
    {
        timeindex[i] = f->GetWord();
    }
    frames = new tlTransKeyData[numkeys];
    for(i = 0; i < numkeys; i++)
    {
        frames[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_CHANNEL_3DOF);
    }
}

