tlChannel3DOFChunk16&
tlChannel3DOFChunk16::operator=(const tlChannel3DOFChunk16& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numkeys = a.numkeys;
    if(timeindex)
    {
        delete timeindex;
    }
    timeindex = new unsigned short[numkeys];
    for( i = 0; i < numkeys ; i++ )
    {
        timeindex[i] = a.timeindex[i];
    }
    if(frames)
    {
        delete frames;
    }
    frames = new tlTransKeyData[numkeys];
    for( i = 0; i < numkeys ; i++ )
    {
        frames[i] = a.frames[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlChannel3DOFChunk16::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlChannel3DOFChunk16* aptr = dynamic_cast<const tlChannel3DOFChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numkeys == aptr->numkeys))
    {
        return false;
    }
    for(i = 0; i < numkeys; i++)
    {
        if(!(timeindex[i] == aptr->timeindex[i]))
        {
            return false;
        }
    }
    for(i = 0; i < numkeys; i++)
    {
        if(!(frames[i] == aptr->frames[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

