int tlChannel1DOFAngleChunk16::sortPriority = -1;

tlChannel1DOFAngleChunk16::tlChannel1DOFAngleChunk16()
{
    Init();
}

tlChannel1DOFAngleChunk16::tlChannel1DOFAngleChunk16(const tlChannel1DOFAngleChunk16& ch)
{
    Init();
    *this = ch;
}

tlChannel1DOFAngleChunk16::~tlChannel1DOFAngleChunk16()
{

    if(constants != NULL){
        delete[] constants;
    }
    if(timeindex != NULL){
        delete[] timeindex;
    }
    if(frames != NULL){
        delete[] frames;
    }
}

tlChannel1DOFAngleChunk16::tlChannel1DOFAngleChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_CHANNEL_1DOF_ANGLE);
    ident = P3D_CHANNEL_1DOF_ANGLE;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numkeys = f->GetLong();
    mapping = f->GetLong();
    numconstants = f->GetLong();
    constants = new float[numconstants];
    for(i = 0; i < numconstants; i++)
    {
        constants[i] = f->GetFloat();
    }
    timeindex = new unsigned short[numkeys];
    for(i = 0; i < numkeys; i++)
    {
        timeindex[i] = f->GetWord();
    }
    frames = new unsigned short[numkeys];
    for(i = 0; i < numkeys; i++)
    {
        frames[i] = f->GetWord();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_CHANNEL_1DOF_ANGLE);
    }
}

void
tlChannel1DOFAngleChunk16::Init()
{
    ident = P3D_CHANNEL_1DOF_ANGLE;
    numkeys = 0;
    mapping = 0;
    numconstants = 0;
    constants = NULL;
    timeindex = NULL;
    frames = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_CHANNEL_1DOF_ANGLE);
    }
}

long 
tlChannel1DOFAngleChunk16::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( numkeys );
    s += sizeof( mapping );
    s += sizeof( numconstants );
    for(i = 0; i < (int)numconstants; i++)
    {
        s += sizeof( constants[i ] );
    }
    for(i = 0; i < (int)numkeys; i++)
    {
        s += sizeof( timeindex[i ] );
    }
    for(i = 0; i < (int)numkeys; i++)
    {
        s += sizeof( frames[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlChannel1DOFAngleChunk16&
tlChannel1DOFAngleChunk16::operator=(const tlChannel1DOFAngleChunk16& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numkeys = a.numkeys;
    mapping = a.mapping;
    numconstants = a.numconstants;
    if(constants)
    {
        delete constants;
    }
    constants = new float[numconstants];
    for( i = 0; i < numconstants ; i++ )
    {
        constants[i] = a.constants[i];
    }
    if(timeindex)
    {
        delete timeindex;
    }
    timeindex = new unsigned short[numkeys];
    for( i = 0; i < numkeys ; i++ )
    {
        timeindex[i] = a.timeindex[i];
    }
    if(frames)
    {
        delete frames;
    }
    frames = new unsigned short[numkeys];
    for( i = 0; i < numkeys ; i++ )
    {
        frames[i] = a.frames[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlChannel1DOFAngleChunk16::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlChannel1DOFAngleChunk16* aptr = dynamic_cast<const tlChannel1DOFAngleChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numkeys == aptr->numkeys))
    {
        return false;
    }
    if(!(mapping == aptr->mapping))
    {
        return false;
    }
    if(!(numconstants == aptr->numconstants))
    {
        return false;
    }
    for(i = 0; i < numconstants; i++)
    {
        if(!(constants[i] == aptr->constants[i]))
        {
            return false;
        }
    }
    for(i = 0; i < numkeys; i++)
    {
        if(!(timeindex[i] == aptr->timeindex[i]))
        {
            return false;
        }
    }
    for(i = 0; i < numkeys; i++)
    {
        if(!(frames[i] == aptr->frames[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

