int tlKeyListColourChunk16::sortPriority = -1;

tlKeyListColourChunk16::tlKeyListColourChunk16()
{
    Init();
}

tlKeyListColourChunk16::tlKeyListColourChunk16(const tlKeyListColourChunk16& ch)
{
    Init();
    *this = ch;
}

tlKeyListColourChunk16::~tlKeyListColourChunk16()
{

    if(frames != NULL){
        delete[] frames;
    }
    if(keys != NULL){
        delete[] keys;
    }
}

tlKeyListColourChunk16::tlKeyListColourChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_KEYLIST_COLOUR);
    ident = P3D_KEYLIST_COLOUR;

    tlFile* f = ch->GetFile();
    unsigned int i;

    numkeys = f->GetLong();
    frames = new unsigned short[numkeys];
    for(i = 0; i < numkeys; i++)
    {
        frames[i] = f->GetWord();
    }
    keys = new unsigned long[numkeys];
    for(i = 0; i < numkeys; i++)
    {
        keys[i] = f->GetLong();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_KEYLIST_COLOUR);
    }
}

void
tlKeyListColourChunk16::Init()
{
    ident = P3D_KEYLIST_COLOUR;
    numkeys = 0;
    frames = NULL;
    keys = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_KEYLIST_COLOUR);
    }
}

long 
tlKeyListColourChunk16::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( numkeys );
    for(i = 0; i < (int)numkeys; i++)
    {
        s += sizeof( frames[i ] );
    }
    for(i = 0; i < (int)numkeys; i++)
    {
        s += sizeof( keys[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlKeyListColourChunk16&
tlKeyListColourChunk16::operator=(const tlKeyListColourChunk16& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numkeys = a.numkeys;
    if(frames)
    {
        delete frames;
    }
    frames = new unsigned short[numkeys];
    for( i = 0; i < numkeys ; i++ )
    {
        frames[i] = a.frames[i];
    }
    if(keys)
    {
        delete keys;
    }
    keys = new unsigned long[numkeys];
    for( i = 0; i < numkeys ; i++ )
    {
        keys[i] = a.keys[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlKeyListColourChunk16::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlKeyListColourChunk16* aptr = dynamic_cast<const tlKeyListColourChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numkeys == aptr->numkeys))
    {
        return false;
    }
    for(i = 0; i < numkeys; i++)
    {
        if(!(frames[i] == aptr->frames[i]))
        {
            return false;
        }
    }
    for(i = 0; i < numkeys; i++)
    {
        if(!(keys[i] == aptr->keys[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

