void
tlKeyListColourChunk16::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(numkeys);
    for(i = 0; i < numkeys ; i++)
    {
        f->PutWord(frames[i]);
    }
    for(i = 0; i < numkeys ; i++)
    {
        f->PutLong(keys[i]);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

